from typing import List
import sys
import math
from collections import defaultdict

class Solution:
    def canTraverseAllPairs(self, nums: List[int]) -> bool:
        if len(nums) == 1:
            return True

        # Find all primes up to max(nums) using sieve of Eratosthenes
        max_num = max(nums)
        is_prime = [True] * (max_num + 1)
        is_prime[0] = is_prime[1] = False
        for i in range(2, int(max_num ** 0.5) + 1):
            if is_prime[i]:
                for j in range(i * i, max_num + 1, i):
                    is_prime[j] = False

        # Build a mapping from prime to list of indices where the number is divisible by that prime
        prime_to_indices = defaultdict(list)
        for idx, num in enumerate(nums):
            temp = num
            i = 2
            while i * i <= temp:
                if is_prime[i] and temp % i == 0:
                    prime_to_indices[i].append(idx)
                    while temp % i == 0:
                        temp //= i
                i += 1
            if temp > 1:
                prime_to_indices[temp].append(idx)

        # Union-Find (DSU) data structure
        parent = list(range(len(nums)))

        def find(u):
            while parent[u] != u:
                parent[u] = parent[parent[u]]
                u = parent[u]
            return u

        def union(u, v):
            pu, pv = find(u), find(v)
            if pu != pv:
                parent[pu] = pv

        # Union indices that share a common prime factor
        for indices in prime_to_indices.values():
            if len(indices) > 1:
                first = indices[0]
                for idx in indices[1:]:
                    union(first, idx)

        # Check if all indices are connected
        root = find(0)
        for i in range(1, len(nums)):
            if find(i) != root:
                return False
        return True
